  8→const migrationsFolder = join(
  9→	import.meta.dir,
 10→	"..",
 11→	"..",
 12→	"..",
 13→	"packages",
 14→	"sql-schema",
 15→	"db",
 16→	"migrations",
 17→);
 18→migrate(db, { migrationsFolder });
