 20→const socialProviders: Record<
 21→	string,
 22→	{ clientId: string; clientSecret: string }
 23→> = {};
 24→if (process.env.GOOGLE_CLIENT_ID && process.env.GOOGLE_CLIENT_SECRET) {
 25→	socialProviders.google = {
 26→		clientId: process.env.GOOGLE_CLIENT_ID,
 27→		clientSecret: process.env.GOOGLE_CLIENT_SECRET,
 28→	};
 29→}
 30→if (process.env.GITHUB_CLIENT_ID && process.env.GITHUB_CLIENT_SECRET) {
 31→	socialProviders.github = {
 32→		clientId: process.env.GITHUB_CLIENT_ID,
 33→		clientSecret: process.env.GITHUB_CLIENT_SECRET,
 34→	};
 35→}
 36→
 37→const appURL = process.env.APP_URL ?? "http://localhost:4010";
 38→const trustedOrigins = process.env.TRUSTED_ORIGINS
 39→	? process.env.TRUSTED_ORIGINS.split(",").map((o) => o.trim())
 40→	: ["http://localhost:4011"];
 41→
 42→const auth = createAuth(db, {
 43→	appURL,
 44→	secret: process.env.BETTER_AUTH_SECRET,
 45→	socialProviders,
 46→	trustedOrigins,
 47→});
 48→
 49→const rpcHandler = new RPCHandler(router);
 50→
 51→const ALLOWED_ORIGIN = process.env.ALLOWED_ORIGIN ?? "http://localhost:4011";
 52→const STATIC_DIR = join(
 53→	import.meta.dir,
 54→	"..",
 55→	process.env.STATIC_DIR ?? "public",
 56→);
 57→
 58→function corsHeaders(origin: string | null): Record<string, string> {
 59→	if (origin !== ALLOWED_ORIGIN) return {};
 60→	return {
 61→		"Access-Control-Allow-Origin": ALLOWED_ORIGIN,
 62→		"Access-Control-Allow-Credentials": "true",
 63→		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
 64→		"Access-Control-Allow-Headers": "Content-Type, Authorization",
 65→	};
 66→}
 67→
 68→const port = process.env.PORT ?? 4010;
 69→
 70→Bun.serve({
 71→	port,
 72→	async fetch(request) {
 73→		const origin = request.headers.get("Origin");
 74→		const cors = corsHeaders(origin);
 75→
 76→		if (request.method === "OPTIONS") {
 77→			return new Response(null, { status: 204, headers: cors });
 78→		}
 79→
 80→		const url = new URL(request.url);
 81→
 82→		if (url.pathname === "/api/cli-token") {
 83→			const session = await auth.api.getSession({
 84→				headers: request.headers,
 85→			});
 86→			if (!session) {
 87→				return new Response(JSON.stringify({ error: "Not authenticated" }), {
 88→					status: 401,
 89→					headers: { ...cors, "Content-Type": "application/json" },
 90→				});
 91→			}
 92→			return new Response(JSON.stringify({ token: session.session.token }), {
 93→				status: 200,
 94→				headers: { ...cors, "Content-Type": "application/json" },
 95→			});
 96→		}
 97→
 98→		if (url.pathname.startsWith("/api/auth")) {
 99→			const response = await auth.handler(request);
100→			for (const [key, value] of Object.entries(cors)) {
101→				response.headers.set(key, value);
102→			}
103→			return response;
104→		}
105→
106→		const { matched, response } = await rpcHandler.handle(request, {
107→			prefix: "/rpc",
108→			context: await getContext(request),
109→		});
110→
111→		if (matched) {
112→			for (const [key, value] of Object.entries(cors)) {
113→				response.headers.set(key, value);
114→			}
115→			return response;
116→		}
117→
118→		// Static file serving (production: frontend assets)
119→		const filePath = join(STATIC_DIR, url.pathname);
120→		const file = Bun.file(filePath);
121→		if (await file.exists()) {
122→			return new Response(file);
123→		}
124→
125→		// SPA fallback: serve index.html for non-API routes
126→		const indexFile = Bun.file(join(STATIC_DIR, "index.html"));
127→		if (await indexFile.exists()) {
128→			return new Response(indexFile);
129→		}
130→
131→		return new Response("Not found", { status: 404, headers: cors });
132→	},
133→});
134→
135→async function getContext(request: Request) {
136→	const session = await auth.api.getSession({
137→		headers: request.headers,
138→	});
139→	return {
140→		user: session?.user ?? null,
141→		session: session?.session ?? null,
142→	};
143→}
144→
145→console.log(`API server listening on http://localhost:${port}`);
