 26→function buildRouter() {
 27→	const health = os.health.handler(() => ({
 28→		status: "ok" as const,
 29→		timestamp: Date.now(),
 30→	}));
 31→
 32→	const me = os.me.use(authMiddleware).handler(({ context }) => ({
 33→		id: context.user.id,
 34→		email: context.user.email,
 35→		name: context.user.name,
 36→	}));
 37→
 38→	const ingestSessionHandler = os.ingestSession
 39→		.use(authMiddleware)
 40→		.handler(async ({ input, context }) => {
 41→			await ingestSession(getClickhouse(), input, {
 42→				userId: context.user.id,
 43→				organizationId: context.user.id,
 44→			});
 45→			return { success: true as const, sessionId: input.sessionId };
 46→		});
 47→
 48→	return os.router({ health, me, ingestSession: ingestSessionHandler });
 49→}
