 1→import { buildCommand } from "@stricli/core";
 2→import { loadCredentials } from "../../../lib/credentials.js";
 3→import { getGitInfo } from "../../../lib/git-info.js";
 4→import { readSubagentFiles } from "../../../lib/subagent-reader.js";
 5→import {
 6→	extractAgentIds,
 7→	readTranscript,
 8→} from "../../../lib/transcript-reader.js";
 9→import type { IngestRequest } from "../../../lib/types.js";
10→import { uploadSession } from "../../../lib/uploader.js";
11→
12→interface HookInput {
13→	session_id: string;
14→	transcript_path: string;
15→	cwd: string;
16→}
17→
18→async function readStdin(): Promise<string> {
19→	const chunks: string[] = [];
20→	for await (const chunk of process.stdin) {
21→		chunks.push(typeof chunk === "string" ? chunk : chunk.toString());
22→	}
23→	return chunks.join("");
24→}
25→
26→async function runSessionEnd(): Promise<void> {
27→	try {
28→		const raw = await readStdin();
29→		if (!raw.trim()) return;
30→
31→		const input = JSON.parse(raw) as HookInput;
32→		if (!input.session_id || !input.transcript_path) return;
33→
34→		const credentials = loadCredentials();
35→		if (!credentials) return;
36→
37→		const content = await readTranscript(input.transcript_path);
38→
39→		const agentIds = extractAgentIds(content);
40→		const { dirname } = await import("node:path");
41→		const sessionDir = dirname(input.transcript_path);
42→		const subagents =
43→			agentIds.length > 0
44→				? await readSubagentFiles(sessionDir, agentIds, input.session_id)
45→				: [];
46→
47→		const gitInfo = await getGitInfo(input.cwd);
48→
49→		const request: IngestRequest = {
50→			sessionId: input.session_id,
51→			projectPath: input.cwd,
52→			repository: gitInfo.repository,
53→			gitBranch: gitInfo.branch,
54→			gitSha: gitInfo.sha,
55→			content,
56→			subagents: subagents.length > 0 ? subagents : undefined,
57→		};
58→
59→		const endpoint = `${credentials.apiBaseUrl}/rpc`;
60→		await uploadSession(request, { endpoint, token: credentials.token });
61→	} catch {
62→		// Swallow all errors — this runs async in the background
63→	}
64→}
65→
66→export const sessionEndCommand = buildCommand({
67→	loader: async () => ({ default: runSessionEnd }),
68→	parameters: {},
69→	docs: {
70→		brief: "Handle Claude Code SessionEnd hook",
71→	},
72→});
