  1→import { execSync } from "node:child_process";
  2→import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
  3→import { join } from "node:path";
  4→
  5→const HOOK_COMMAND = "rudel hooks claude session-end";
  6→
  7→function findGitRoot(): string {
  8→	return execSync("git rev-parse --show-toplevel", {
  9→		encoding: "utf-8",
 10→	}).trim();
 11→}
 12→
 13→interface HookEntry {
 14→	type: string;
 15→	command: string;
 16→	async?: boolean;
 17→}
 18→
 19→interface HookMatcher {
 20→	matcher: string;
 21→	hooks: HookEntry[];
 22→}
 23→
 24→interface ClaudeSettings {
 25→	hooks?: {
 26→		SessionEnd?: HookMatcher[];
 27→		[key: string]: unknown;
 28→	};
 29→	[key: string]: unknown;
 30→}
 31→
 32→export function getClaudeSettingsPath(): string {
 33→	const root = findGitRoot();
 34→	return join(root, ".claude", "settings.json");
 35→}
 36→
 37→export function readClaudeSettings(): ClaudeSettings {
 38→	const path = getClaudeSettingsPath();
 39→	if (!existsSync(path)) return {};
 40→	const content = readFileSync(path, "utf-8");
 41→	return JSON.parse(content) as ClaudeSettings;
 42→}
 43→
 44→export function writeClaudeSettings(settings: ClaudeSettings): void {
 45→	const path = getClaudeSettingsPath();
 46→	const dir = join(path, "..");
 47→	if (!existsSync(dir)) {
 48→		mkdirSync(dir, { recursive: true });
 49→	}
 50→	writeFileSync(path, `${JSON.stringify(settings, null, 2)}\n`);
 51→}
 52→
 53→export function isHookEnabled(): boolean {
 54→	const settings = readClaudeSettings();
 55→	const entries = settings.hooks?.SessionEnd;
 56→	if (!Array.isArray(entries)) return false;
 57→	return entries.some((entry) =>
 58→		entry.hooks?.some((h) => h.command === HOOK_COMMAND),
 59→	);
 60→}
 61→
 62→export function addHook(): void {
 63→	const settings = readClaudeSettings();
 64→	if (!settings.hooks) {
 65→		settings.hooks = {};
 66→	}
 67→	if (!Array.isArray(settings.hooks.SessionEnd)) {
 68→		settings.hooks.SessionEnd = [];
 69→	}
 70→
 71→	const alreadyExists = settings.hooks.SessionEnd.some((entry) =>
 72→		entry.hooks?.some((h) => h.command === HOOK_COMMAND),
 73→	);
 74→	if (alreadyExists) return;
 75→
 76→	settings.hooks.SessionEnd.push({
 77→		matcher: "",
 78→		hooks: [{ type: "command", command: HOOK_COMMAND, async: true }],
 79→	});
 80→
 81→	writeClaudeSettings(settings);
 82→}
 83→
 84→export function removeHook(): void {
 85→	const settings = readClaudeSettings();
 86→	const hooks = settings.hooks;
 87→	const entries = hooks?.SessionEnd;
 88→	if (!hooks || !Array.isArray(entries)) return;
 89→
 90→	hooks.SessionEnd = entries.filter(
 91→		(entry) => !entry.hooks?.some((h) => h.command === HOOK_COMMAND),
 92→	);
 93→
 94→	if (hooks.SessionEnd.length === 0) {
 95→		delete hooks.SessionEnd;
 96→	}
 97→	if (Object.keys(hooks).length === 0) {
 98→		delete settings.hooks;
 99→	}
100→
101→	writeClaudeSettings(settings);
102→}
