 87→const testId = `api_test_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
 88→
 89→const baseExecutor = createClickHouseExecutor({
 90→	url: process.env.CLICKHOUSE_URL || "http://localhost:8123",
 91→	username:
 92→		process.env.CLICKHOUSE_USERNAME || process.env.CLICKHOUSE_USER || "default",
 93→	password: process.env.CLICKHOUSE_PASSWORD || "",
 94→	database: "default",
 95→});
 96→
 97→// ClickHouse Cloud's @clickhouse/client insert() silently drops data.
 98→// Wrap the executor to use execute() with FORMAT JSONEachRow instead.
 99→// async_insert=0 forces synchronous insert so data is immediately queryable.
100→const executor: typeof baseExecutor = {
101→	...baseExecutor,
102→	async insert(params) {
103→		const rows = params.values
104→			.map((r: Record<string, unknown>) => JSON.stringify(r))
105→			.join("\n");
106→		await baseExecutor.execute(
107→			`INSERT INTO ${params.table} SETTINGS async_insert=0 FORMAT JSONEachRow ${rows}`,
108→		);
109→	},
110→};
111→
112→afterAll(() => {
113→	// Fire-and-forget: ClickHouse Cloud DELETE mutations are slow
114→	executor
115→		.execute(`DELETE FROM flick.claude_sessions WHERE session_id = '${testId}'`)
116→		.catch(() => {});
117→});
118→
119→async function waitForRow(
120→	sessionId: string,
121→	timeoutMs = 30000,
122→	intervalMs = 2000,
123→): Promise<
124→	Array<{
125→		session_id: string;
126→		project_path: string;
127→		repository: string;
128→		tag: string;
129→		user_id: string;
130→		organization_id: string;
131→	}>
132→> {
133→	const start = Date.now();
134→	while (Date.now() - start < timeoutMs) {
135→		try {
136→			const results = await executor.query<{
137→				session_id: string;
138→				project_path: string;
139→				repository: string;
140→				tag: string;
141→				user_id: string;
142→				organization_id: string;
143→			}>(
144→				`SELECT session_id, project_path, repository, tag, user_id, organization_id FROM flick.claude_sessions WHERE session_id = '${sessionId}' LIMIT 1`,
145→			);
146→			if (results.length > 0) return results;
147→		} catch {
148→			// Transient ClickHouse errors (e.g. S3 storage) - retry
149→		}
150→		await new Promise((r) => setTimeout(r, intervalMs));
151→	}
152→	return [];
153→}
154→
155→describe("ingestSession", () => {
156→	test("ingests a session into ClickHouse and reads it back", async () => {
157→		const input: IngestSessionInput = {
158→			sessionId: testId,
159→			projectPath: "/test/api-ingest",
160→			repository: "test-repo",
161→			gitBranch: "feature-branch",
162→			gitSha: "deadbeef",
163→			tag: "tests",
164→			content: "integration test content",
165→			subagents: [{ agentId: "sub-1", content: "subagent content" }],
166→		};
167→
168→		// ClickHouse Cloud can silently drop inserts or throw race condition
169→		// errors (code 236). Retry the insert+read cycle with exponential backoff.
170→		let results: Awaited<ReturnType<typeof waitForRow>> = [];
171→		for (let attempt = 0; attempt < 5; attempt++) {
172→			try {
173→				await ingestSession(executor, input, {
174→					userId: "test_user",
175→					organizationId: "test_org",
176→				});
177→			} catch {
178→				await new Promise((r) => setTimeout(r, 2000 * 2 ** attempt));
179→				continue;
180→			}
181→			results = await waitForRow(testId);
182→			if (results.length > 0) break;
183→		}
184→
185→		expect(results).toHaveLength(1);
186→		expect(results[0]?.session_id).toBe(testId);
187→		expect(results[0]?.project_path).toBe("/test/api-ingest");
188→		expect(results[0]?.repository).toBe("test-repo");
189→		expect(results[0]?.tag).toBe("tests");
190→		expect(results[0]?.user_id).toBe("test_user");
191→		expect(results[0]?.organization_id).toBe("test_org");
192→	}, 120000);
193→});
