  1→#!/usr/bin/env bun
  2→/**
  3→ * Release script for the `rudel` CLI package.
  4→ *
  5→ * Handles the full release lifecycle:
  6→ *   1. Prerequisite checks (tools, branch, npm auth)
  7→ *   2. Bumps the version (patch or minor)
  8→ *   3. Runs quality gates (typecheck, lint, test, build)
  9→ *   4. Publishes via `bun publish`
 10→ *   5. Commits version changes, tags, and pushes
 11→ *
 12→ * Usage: bun run ./scripts/release-cli.ts [patch|minor] [--dry-run]
 13→ */
 14→import { spawnSync } from "node:child_process";
 15→import { readFileSync, writeFileSync } from "node:fs";
 16→import { resolve } from "node:path";
 17→import process, { stdin, stdout } from "node:process";
 18→import { createInterface } from "node:readline/promises";
 19→
 20→type ReleaseArgs = {
 21→	bump: "patch" | "minor";
 22→	dryRun: boolean;
 23→};
 24→
 25→type CommandResult = {
 26→	stdout: string;
 27→	stderr: string;
 28→};
 29→
 30→type PackageJson = {
 31→	name: string;
 32→	version: string;
 33→};
 34→
 35→const CLI_DIR = resolve("apps/cli");
 36→const CLI_PKG_PATH = resolve(CLI_DIR, "package.json");
 37→const APP_TS_PATH = resolve(CLI_DIR, "src/app.ts");
 38→
 39→export async function main(): Promise<void> {
 40→	const args = parseArgs(process.argv.slice(2));
 41→
 42→	// 1. Prerequisites
 43→	logLine("Checking prerequisites...");
 44→	ensureRequiredTools();
 45→	ensureOnMainBranch();
 46→	ensureCleanWorkingTree();
 47→	ensureNpmAuth();
 48→
 49→	// 2. Version bump
 50→	const pkg = readCliPackageJson();
 51→	const currentVersion = pkg.version;
 52→	const nextVersion = bumpVersion(currentVersion, args.bump);
 53→
 54→	logLine(`Version: ${currentVersion} -> ${nextVersion} (${args.bump})`);
 55→
 56→	if (args.dryRun) {
 57→		logLine("Dry-run: would update version and publish. Stopping here.");
 58→		return;
 59→	}
 60→
 61→	writeCliVersion(nextVersion);
 62→
 63→	// 3. Quality gates
 64→	runQualityGates();
 65→
 66→	// 4. Publish
 67→	const otp = await promptForOtp();
 68→	publishCli(otp);
 69→
 70→	// 5. Commit, tag, push
 71→	commitTagAndPush(nextVersion);
 72→
 73→	logLine(`Released rudel@${nextVersion}`);
 74→}
 75→
 76→// ---------------------------------------------------------------------------
 77→// Version management
 78→// ---------------------------------------------------------------------------
 79→
 80→function readCliPackageJson(): PackageJson {
 81→	return JSON.parse(readFileSync(CLI_PKG_PATH, "utf8")) as PackageJson;
 82→}
 83→
 84→function bumpVersion(current: string, bump: "patch" | "minor"): string {
 85→	const parts = current.split(".").map(Number);
 86→	if (parts.length !== 3 || parts.some(Number.isNaN)) {
 87→		fail(`Invalid version format: ${current}`);
 88→	}
 89→	const [major, minor, patch] = parts;
 90→
 91→	if (bump === "minor") {
 92→		return `${major}.${minor + 1}.0`;
 93→	}
 94→	return `${major}.${minor}.${patch + 1}`;
 95→}
 96→
 97→function writeCliVersion(version: string): void {
 98→	// Update package.json
 99→	const pkg = JSON.parse(readFileSync(CLI_PKG_PATH, "utf8"));
100→	pkg.version = version;
101→	writeFileSync(CLI_PKG_PATH, `${JSON.stringify(pkg, null, "\t")}\n`);
102→
103→	// Update hardcoded version in app.ts
104→	const appTs = readFileSync(APP_TS_PATH, "utf8");
105→	const updated = appTs.replace(
106→		/currentVersion:\s*"[^"]+"/,
107→		`currentVersion: "${version}"`,
108→	);
109→	if (updated === appTs) {
110→		fail("Could not find currentVersion in app.ts to update");
111→	}
112→	writeFileSync(APP_TS_PATH, updated);
113→
114→	logLine(`Updated version to ${version} in package.json and app.ts`);
115→}
116→
117→// ---------------------------------------------------------------------------
118→// Publishing
119→// ---------------------------------------------------------------------------
120→
121→function publishCli(otp: string): void {
122→	const pkg = readCliPackageJson();
123→
124→	if (isVersionPublished(pkg.name, pkg.version)) {
125→		fail(`${pkg.name}@${pkg.version} is already published on npm.`);
126→	}
127→
128→	logLine(`Publishing ${pkg.name}@${pkg.version}...`);
129→	runCommand("bun", ["publish", "--access", "public", "--otp", otp], {
130→		cwd: CLI_DIR,
131→	});
132→}
133→
134→function isVersionPublished(name: string, version: string): boolean {
135→	const result = spawnSync("npm", ["view", `${name}@${version}`, "version"], {
136→		encoding: "utf8",
137→		env: process.env,
138→	});
139→	return result.status === 0 && result.stdout.trim() === version;
140→}
141→
142→// ---------------------------------------------------------------------------
143→// Git
144→// ---------------------------------------------------------------------------
145→
146→function commitTagAndPush(version: string): void {
147→	const tag = `rudel@${version}`;
148→
149→	logLine("Committing version changes...");
150→	runCommand("git", ["add", CLI_PKG_PATH, APP_TS_PATH]);
151→	runCommand("git", ["commit", "-m", `chore: release rudel@${version}`]);
152→	runCommand("git", ["tag", tag]);
153→	runCommand("git", ["push", "origin", "main"]);
154→	runCommand("git", ["push", "origin", tag]);
155→
156→	logLine(`Tagged ${tag} and pushed to origin/main`);
157→}
158→
159→// ---------------------------------------------------------------------------
160→// Preconditions
161→// ---------------------------------------------------------------------------
162→
163→function parseArgs(argv: string[]): ReleaseArgs {
164→	let bump: "patch" | "minor" = "patch";
165→	let dryRun = false;
166→
167→	for (const arg of argv) {
168→		if (arg === "patch" || arg === "minor") {
169→			bump = arg;
170→			continue;
171→		}
172→		if (arg === "--dry-run") {
173→			dryRun = true;
174→			continue;
175→		}
176→		fail(`Unknown argument: ${arg}. Usage: release-cli.ts [patch|minor] [--dry-run]`);
177→	}
178→
179→	return { bump, dryRun };
180→}
181→
182→function ensureRequiredTools(): void {
183→	runCommand("bun", ["--version"]);
184→	runCommand("git", ["--version"]);
185→	runCommand("npm", ["--version"]);
186→}
187→
188→function ensureOnMainBranch(): void {
189→	const result = runCommand("git", ["rev-parse", "--abbrev-ref", "HEAD"]);
190→	const branch = result.stdout.trim();
191→	if (branch !== "main") {
192→		fail(`Release must run on main. Current branch: ${branch}`);
193→	}
194→}
195→
196→function ensureCleanWorkingTree(): void {
197→	const result = runCommand("git", ["status", "--porcelain"]);
198→	if (result.stdout.trim().length > 0) {
199→		fail("Working tree is not clean. Commit or stash changes first.");
200→	}
201→}
202→
203→function ensureNpmAuth(): void {
204→	runCommand("npm", ["whoami"]);
205→}
206→
207→function runQualityGates(): void {
208→	logLine("Running quality gates (lint, typecheck, test, build)...");
209→	runCommand("bun", ["run", "verify"]);
210→}
211→
212→// ---------------------------------------------------------------------------
213→// Utilities
214→// ---------------------------------------------------------------------------
215→
216→async function promptForOtp(): Promise<string> {
217→	const rl = createInterface({ input: stdin, output: stdout });
218→	try {
219→		const otp = await rl.question("Enter npm OTP to publish: ");
220→		const trimmed = otp.trim();
221→		if (trimmed.length === 0) {
222→			fail("No OTP provided. Publish cancelled.");
223→		}
224→		return trimmed;
225→	} finally {
226→		rl.close();
227→	}
228→}
229→
230→function runCommand(
231→	command: string,
232→	args: string[],
233→	options?: { cwd?: string },
234→): CommandResult {
235→	const rendered = `${command} ${args.map(shellQuote).join(" ")}`;
236→	logLine(`$ ${rendered}`);
237→
238→	const result = spawnSync(command, args, {
239→		cwd: options?.cwd ?? process.cwd(),
240→		encoding: "utf8",
241→		env: process.env,
242→	});
243→
244→	const stdoutText = result.stdout ?? "";
245→	const stderrText = result.stderr ?? "";
246→
247→	if (stdoutText.length > 0) {
248→		process.stdout.write(stdoutText);
249→	}
250→	if (stderrText.length > 0) {
251→		process.stderr.write(stderrText);
252→	}
253→
254→	if (result.status !== 0) {
255→		fail(`Command failed (${result.status}): ${rendered}`);
256→	}
257→
258→	return { stdout: stdoutText, stderr: stderrText };
259→}
260→
261→function shellQuote(value: string): string {
262→	if (/^[A-Za-z0-9_./:-]+$/.test(value)) {
263→		return value;
264→	}
265→	return `'${value.replaceAll("'", "'\\''")}'`;
266→}
267→
268→function logLine(message: string): void {
269→	process.stdout.write(`${message}\n`);
270→}
271→
272→function fail(message: string): never {
273→	logLine(`ERROR: ${message}`);
274→	process.exit(1);
275→}
276→
277→await main();
278→

