 71→	port,
 72→	async fetch(request) {
 73→		const origin = request.headers.get("Origin");
 74→		const cors = corsHeaders(origin);
 75→
 76→		if (request.method === "OPTIONS") {
 77→			return new Response(null, { status: 204, headers: cors });
 78→		}
 79→
 80→		const url = new URL(request.url);
 81→
 82→		if (url.pathname === "/api/cli-token") {
 83→			const session = await auth.api.getSession({
 84→				headers: request.headers,
 85→			});
 86→			if (!session) {
 87→				return new Response(JSON.stringify({ error: "Not authenticated" }), {
 88→					status: 401,
 89→					headers: { ...cors, "Content-Type": "application/json" },
 90→				});
 91→			}
 92→			return new Response(JSON.stringify({ token: session.session.token }), {
 93→				status: 200,
 94→				headers: { ...cors, "Content-Type": "application/json" },
 95→			});
 96→		}
 97→
 98→		if (url.pathname.startsWith("/api/auth")) {
 99→			const response = await auth.handler(request);
100→			for (const [key, value] of Object.entries(cors)) {
101→				response.headers.set(key, value);
102→			}
103→			return response;
104→		}
105→
106→		const { matched, response } = await rpcHandler.handle(request, {
107→			prefix: "/rpc",
108→			context: await getContext(request),
109→		});
110→
111→		if (matched) {
112→			for (const [key, value] of Object.entries(cors)) {
113→				response.headers.set(key, value);
114→			}
115→			return response;
116→		}
117→
118→		// Static file serving (production: frontend assets)
119→		const filePath = join(STATIC_DIR, url.pathname);
120→		const file = Bun.file(filePath);
121→		if (await file.exists()) {
122→			return new Response(file);
123→		}
124→
125→		// SPA fallback: serve index.html for non-API routes
126→		const indexFile = Bun.file(join(STATIC_DIR, "index.html"));
127→		if (await indexFile.exists()) {
128→			return new Response(indexFile);
129→		}
130→
131→		return new Response("Not found", { status: 404, headers: cors });
132→	},
133→});
