  1→#!/usr/bin/env bun
  2→/**
  3→ * Release script for the `rudel` CLI package.
  4→ *
  5→ * Handles the full release lifecycle:
  6→ *   1. Prerequisite checks (tools, branch, npm auth)
  7→ *   2. Bumps the version (patch or minor)
  8→ *   3. Runs quality gates (typecheck, lint, test, build)
  9→ *   4. Publishes via `bun publish`
 10→ *   5. Commits version changes, tags, and pushes
 11→ *
 12→ * Usage: bun run ./scripts/release-cli.ts [patch|minor] [--dry-run]
 13→ */
 14→import { spawnSync } from "node:child_process";
 15→import { readFileSync, writeFileSync } from "node:fs";
 16→import { resolve } from "node:path";
 17→import process, { stdin, stdout } from "node:process";
 18→import { createInterface } from "node:readline/promises";
 19→
 20→type ReleaseArgs = {
 21→	bump: "patch" | "minor";
 22→	dryRun: boolean;
 23→};
 24→
 25→type CommandResult = {
 26→	stdout: string;
 27→	stderr: string;
 28→};
 29→
 30→type PackageJson = {
 31→	name: string;
 32→	version: string;
 33→};
 34→
 35→const CLI_DIR = resolve("apps/cli");
 36→const CLI_PKG_PATH = resolve(CLI_DIR, "package.json");
 37→const APP_TS_PATH = resolve(CLI_DIR, "src/app.ts");
 38→
 39→export async function main(): Promise<void> {
 40→	const args = parseArgs(process.argv.slice(2));
 41→
 42→	// 1. Prerequisites
 43→	logLine("Checking prerequisites...");
 44→	ensureRequiredTools();
 45→	ensureOnMainBranch();
 46→	ensureCleanWorkingTree();
 47→	ensureNpmAuth();
 48→
 49→	// 2. Version bump
 50→	const pkg = readCliPackageJson();
 51→	const currentVersion = pkg.version;
 52→	const nextVersion = bumpVersion(currentVersion, args.bump);
 53→
 54→	logLine(`Version: ${currentVersion} -> ${nextVersion} (${args.bump})`);
 55→
 56→	if (args.dryRun) {
 57→		logLine("Dry-run: would update version and publish. Stopping here.");
 58→		return;
 59→	}
 60→
 61→	writeCliVersion(nextVersion);
 62→
 63→	// 3. Quality gates
 64→	runQualityGates();
 65→
 66→	// 4. Publish
 67→	const otp = await promptForOtp();
 68→	publishCli(otp);
 69→
 70→	// 5. Commit, tag, push
 71→	commitTagAndPush(nextVersion);
 72→
 73→	logLine(`Released rudel@${nextVersion}`);
 74→}
 75→
 76→// ---------------------------------------------------------------------------
 77→// Version management
 78→// ---------------------------------------------------------------------------
 79→
 80→function readCliPackageJson(): PackageJson {
 81→	return JSON.parse(readFileSync(CLI_PKG_PATH, "utf8")) as PackageJson;
 82→}
 83→
 84→function bumpVersion(current: string, bump: "patch" | "minor"): string {
 85→	const parts = current.split(".").map(Number);
 86→	if (parts.length !== 3 || parts.some(Number.isNaN)) {
 87→		fail(`Invalid version format: ${current}`);
 88→	}
 89→	const [major, minor, patch] = parts;
 90→
 91→	if (bump === "minor") {
 92→		return `${major}.${minor + 1}.0`;
 93→	}
 94→	return `${major}.${minor}.${patch + 1}`;
 95→}
 96→
 97→function writeCliVersion(version: string): void {
 98→	// Update package.json
 99→	const pkg = JSON.parse(readFileSync(CLI_PKG_PATH, "utf8"));
100→	pkg.version = version;
101→	writeFileSync(CLI_PKG_PATH, `${JSON.stringify(pkg, null, "\t")}\n`);
102→
103→	// Update hardcoded version in app.ts
104→	const appTs = readFileSync(APP_TS_PATH, "utf8");
105→	const updated = appTs.replace(
106→		/currentVersion:\s*"[^"]+"/,
107→		`currentVersion: "${version}"`,
108→	);
109→	if (updated === appTs) {
110→		fail("Could not find currentVersion in app.ts to update");
111→	}
112→	writeFileSync(APP_TS_PATH, updated);
113→
114→	logLine(`Updated version to ${version} in package.json and app.ts`);
115→}
116→
117→// ---------------------------------------------------------------------------
118→// Publishing
119→// ---------------------------------------------------------------------------
120→
121→function publishCli(otp: string): void {
122→	const pkg = readCliPackageJson();
123→
124→	if (isVersionPublished(pkg.name, pkg.version)) {
125→		fail(`${pkg.name}@${pkg.version} is already published on npm.`);
126→	}
127→
128→	logLine(`Publishing ${pkg.name}@${pkg.version}...`);
129→	runCommand("bun", ["publish", "--access", "public", "--otp", otp], {
