146→function commitTagAndPush(version: string): void {
147→	const tag = `rudel@${version}`;
148→
149→	logLine("Committing version changes...");
150→	runCommand("git", ["add", CLI_PKG_PATH, APP_TS_PATH]);
151→	runCommand("git", ["commit", "-m", `chore: release rudel@${version}`]);
152→	runCommand("git", ["tag", tag]);
