162→
163→function parseArgs(argv: string[]): ReleaseArgs {
164→	let bump: "patch" | "minor" = "patch";
165→	let dryRun = false;
166→
167→	for (const arg of argv) {
168→		if (arg === "patch" || arg === "minor") {
169→			bump = arg;
170→			continue;
171→		}
172→		if (arg === "--dry-run") {
173→			dryRun = true;
174→			continue;
175→		}
176→		fail(`Unknown argument: ${arg}. Usage: release-cli.ts [patch|minor] [--dry-run]`);
177→	}
178→
179→	return { bump, dryRun };
180→}
