216→async function promptForOtp(): Promise<string> {
217→	const rl = createInterface({ input: stdin, output: stdout });
218→	try {
219→		const otp = await rl.question("Enter npm OTP to publish: ");
220→		const trimmed = otp.trim();
221→		if (trimmed.length === 0) {
222→			fail("No OTP provided. Publish cancelled.");
223→		}
224→		return trimmed;
225→	} finally {
226→		rl.close();
227→	}
228→}
229→
230→function runCommand(
231→	command: string,
232→	args: string[],
233→	options?: { cwd?: string },
234→): CommandResult {
235→	const rendered = `${command} ${args.map(shellQuote).join(" ")}`;
236→	logLine(`$ ${rendered}`);
237→
238→	const result = spawnSync(command, args, {
239→		cwd: options?.cwd ?? process.cwd(),
240→		encoding: "utf8",
241→		env: process.env,
242→	});
243→
244→	const stdoutText = result.stdout ?? "";
245→	const stderrText = result.stderr ?? "";
246→
247→	if (stdoutText.length > 0) {
248→		process.stdout.write(stdoutText);
249→	}
250→	if (stderrText.length > 0) {
251→		process.stderr.write(stderrText);
252→	}
253→
254→	if (result.status !== 0) {
255→		fail(`Command failed (${result.status}): ${rendered}`);
256→	}
257→
258→	return { stdout: stdoutText, stderr: stderrText };
259→}
260→
261→function shellQuote(value: string): string {
262→	if (/^[A-Za-z0-9_./:-]+$/.test(value)) {
263→		return value;
264→	}
265→	return `'${value.replaceAll("'", "'\\''")}'`;
266→}
267→
268→function logLine(message: string): void {
269→	process.stdout.write(`${message}\n`);
270→}
271→
272→function fail(message: string): never {
273→	logLine(`ERROR: ${message}`);
274→	process.exit(1);
275→}
