119→async function waitForRow(
120→	sessionId: string,
121→	timeoutMs = 30000,
122→	intervalMs = 2000,
123→): Promise<
124→	Array<{
125→		session_id: string;
126→		project_path: string;
127→		repository: string;
128→		tag: string;
129→		user_id: string;
130→		organization_id: string;
131→	}>
132→> {
133→	const start = Date.now();
134→	while (Date.now() - start < timeoutMs) {
135→		try {
136→			const results = await executor.query<{
137→				session_id: string;
138→				project_path: string;
139→				repository: string;
140→				tag: string;
141→				user_id: string;
142→				organization_id: string;
143→			}>(
144→				`SELECT session_id, project_path, repository, tag, user_id, organization_id FROM flick.claude_sessions WHERE session_id = '${sessionId}' LIMIT 1`,
145→			);
146→			if (results.length > 0) return results;
147→		} catch {
148→			// Transient ClickHouse errors (e.g. S3 storage) - retry
149→		}
150→		await new Promise((r) => setTimeout(r, intervalMs));
151→	}
152→	return [];
