  8→const baseExecutor = createClickHouseExecutor({
  9→	url: process.env.CLICKHOUSE_URL || "http://localhost:8123",
 10→	username:
 11→		process.env.CLICKHOUSE_USERNAME || process.env.CLICKHOUSE_USER || "default",
