 16→// ClickHouse Cloud's @clickhouse/client insert() silently drops data.
 17→// Wrap the executor to use execute() with FORMAT JSONEachRow instead.
 18→// async_insert=0 forces synchronous insert so data is immediately queryable.
 19→const executor: typeof baseExecutor = {
 20→	...baseExecutor,
 21→	async insert(params) {
 22→		const rows = params.values
 23→			.map((r: Record<string, unknown>) => JSON.stringify(r))
 24→			.join("\n");
 25→		await baseExecutor.execute(
 26→			`INSERT INTO ${params.table} SETTINGS async_insert=0 FORMAT JSONEachRow ${rows}`,
 27→		);
 28→	},
 29→};
