  2→import { tmpdir } from "node:os";
  3→import { join, resolve } from "node:path";
  4→import type { Subprocess } from "bun";
  5→
  6→const MONOREPO_ROOT = resolve(import.meta.dir, "..", "..", "..", "..", "..");
