 1→import { createClient } from "@clickhouse/client-web";
 2→
 3→export interface ClickHouseExecutor {
 4→	execute(sql: string): Promise<void>;
 5→	query<T>(sql: string): Promise<T[]>;
 6→	insert<T extends Record<string, unknown>>(params: {
 7→		table: string;
 8→		values: T[];
 9→	}): Promise<void>;
10→}
11→
12→export function createClickHouseExecutor(config: {
13→	url: string;
14→	username?: string;
15→	password?: string;
16→	database?: string;
17→}): ClickHouseExecutor {
18→	const client = createClient({
19→		url: config.url,
20→		username: config.username,
21→		password: config.password,
22→		database: config.database,
23→		clickhouse_settings: {
24→			wait_end_of_query: 1,
25→		},
26→	});
27→	return {
28→		async execute(sql) {
29→			await client.command({ query: sql });
30→		},
31→		async query<T>(sql: string): Promise<T[]> {
32→			const result = await client.query({
33→				query: sql,
34→				format: "JSONEachRow",
35→			});
36→			return result.json();
37→		},
38→		async insert(params) {
39→			// Use command() with FORMAT JSONEachRow instead of client.insert()
40→			// because ClickHouse Cloud's @clickhouse/client insert() silently drops data.
41→			const rows = params.values.map((r) => JSON.stringify(r)).join("\n");
42→			await client.command({
43→				query: `INSERT INTO ${params.table} SETTINGS async_insert=0 FORMAT JSONEachRow ${rows}`,
44→			});
45→		},
46→	};
47→}
48→
49→let _clickhouse: ClickHouseExecutor | null = null;
50→
51→export function getClickhouse(): ClickHouseExecutor {
52→	if (!_clickhouse) {
53→		const executor = createClickHouseExecutor({
54→			url: process.env.CLICKHOUSE_URL || "http://localhost:8123",
55→			username:
56→				process.env.CLICKHOUSE_USERNAME ||
57→				process.env.CLICKHOUSE_USER ||
58→				"default",
59→			password: process.env.CLICKHOUSE_PASSWORD || "",
60→			database: "default",
61→		});
62→		const maxRetries = 3;
63→		_clickhouse = {
64→			...executor,
65→			async insert(params) {
66→				for (let attempt = 0; attempt < maxRetries; attempt++) {
67→					try {
68→						return await executor.insert(params);
69→					} catch (error) {
70→						// Retry on INSERT race conditions (ClickHouse code 236)
71→						if (attempt === maxRetries - 1) throw error;
72→						await new Promise((r) => setTimeout(r, 100 * (attempt + 1)));
73→					}
74→				}
75→			},
76→		};
77→	}
78→	return _clickhouse;
79→}
