 15→/**
 16→ * Spawn `wrangler dev` against the real worker entrypoint + D1,
 17→ * writing a temp `.dev.vars` with env vars needed for tests.
 18→ */
 19→export async function startTestWorker(): Promise<TestWorker> {
 20→	const persistDir = await mkdtemp(join(tmpdir(), "rudel-wrangler-test-"));
 21→
 22→	// Build .dev.vars content
 23→	const devVarsLines: string[] = [
 24→		'APP_URL = "http://localhost"',
 25→		'BETTER_AUTH_SECRET = "test-secret-for-integration-tests"',
 26→		'ALLOWED_ORIGIN = "http://localhost"',
 27→	];
 28→
 29→	// Forward ClickHouse vars from the environment (Doppler injects these in CI)
 30→	for (const key of [
 31→		"CLICKHOUSE_URL",
 32→		"CLICKHOUSE_USERNAME",
 33→		"CLICKHOUSE_PASSWORD",
 34→	]) {
 35→		const value =
 36→			process.env[key] ||
 37→			(key === "CLICKHOUSE_USERNAME" ? process.env.CLICKHOUSE_USER : undefined);
 38→		if (value) {
 39→			devVarsLines.push(`${key} = "${value}"`);
 40→		}
 41→	}
 42→
 43→	const devVarsPath = join(persistDir, ".dev.vars");
 44→	await writeFile(devVarsPath, devVarsLines.join("\n"));
 45→
 46→	// Ensure the assets directory exists (wrangler.json references apps/web/dist)
 47→	await mkdir(join(MONOREPO_ROOT, "apps", "web", "dist"), { recursive: true });
 48→
 49→	// Apply D1 migrations so the database schema exists
 50→	const migrateProc = Bun.spawn(
 51→		[
 52→			"npx",
 53→			"wrangler",
 54→			"d1",
 55→			"migrations",
 56→			"apply",
 57→			"rudel",
 58→			"--local",
 59→			`--persist-to=${persistDir}`,
 60→		],
 61→		{
 62→			cwd: MONOREPO_ROOT,
 63→			stdout: "pipe",
 64→			stderr: "pipe",
 65→		},
 66→	);
 67→	await migrateProc.exited;
 68→	if (migrateProc.exitCode !== 0) {
 69→		const stderr = await new Response(migrateProc.stderr).text();
 70→		throw new Error(`D1 migration failed: ${stderr}`);
 71→	}
 72→
 73→	const proc = Bun.spawn(
 74→		[
 75→			"npx",
 76→			"wrangler",
 77→			"dev",
 78→			"--port=0",
 79→			`--persist-to=${persistDir}`,
 80→			`--env-file=${devVarsPath}`,
 81→		],
 82→		{
 83→			cwd: MONOREPO_ROOT,
 84→			stdout: "pipe",
 85→			stderr: "pipe",
 86→			env: {
 87→				...process.env,
 88→			},
 89→		},
 90→	);
 91→
 92→	const port = await parseReadyPort(proc);
 93→
 94→	const baseUrl = `http://localhost:${port}`;
 95→	const rpcUrl = `${baseUrl}/rpc`;
 96→
 97→	return {
 98→		port,
 99→		baseUrl,
100→		rpcUrl,
101→		async stop() {
102→			proc.kill();
103→			await proc.exited;
104→			await rm(persistDir, { recursive: true, force: true }).catch(() => {});
105→		},
106→	};
107→}
108→
109→/**
110→ * Read stdout line-by-line until wrangler prints its "Ready on" URL,
111→ * then extract the port from it.
112→ */
113→async function parseReadyPort(proc: Subprocess): Promise<number> {
114→	const stdout = proc.stdout;
115→	if (!stdout || !(stdout instanceof ReadableStream)) {
116→		throw new Error("wrangler process has no readable stdout");
117→	}
118→
119→	const reader = stdout.getReader();
120→	const decoder = new TextDecoder();
121→	let buffer = "";
122→	const deadline = Date.now() + 30_000;
123→
124→	try {
125→		while (Date.now() < deadline) {
126→			const { value, done } = await reader.read();
127→			if (done) break;
128→			buffer += decoder.decode(value, { stream: true });
129→
130→			// wrangler prints: "Ready on http://localhost:<port>"
131→			const match = buffer.match(/Ready on https?:\/\/localhost:(\d+)/i);
132→			if (match?.[1]) {
133→				reader.releaseLock();
134→				return Number.parseInt(match[1], 10);
135→			}
136→		}
137→	} catch {
138→		// reader error — fall through to throw
139→	}
140→
141→	// If we get here we failed — grab stderr for diagnostics
142→	let stderrText = "";
143→	if (proc.stderr instanceof ReadableStream) {
144→		stderrText = await new Response(proc.stderr).text();
145→	}
146→
147→	proc.kill();
148→	throw new Error(
149→		`wrangler dev did not become ready within 30 s.\nstdout buffer: ${buffer}\nstderr: ${stderrText}`,
150→	);
151→}
