178→// Helpers that operate on a specific config dir (matching the RUDEL_CONFIG_DIR env var)
179→function saveCredentialsToDir(
180→	dir: string,
181→	token: string,
182→	apiBaseUrl: string,
183→): void {
184→	const { writeFileSync } = require("node:fs");
185→	writeFileSync(
186→		join(dir, "credentials.json"),
187→		JSON.stringify({ token, apiBaseUrl }, null, 2),
188→		{ mode: 0o600 },
189→	);
190→}
191→
192→function loadCredentialsFromDir(
193→	dir: string,
194→): { token: string; apiBaseUrl: string } | null {
195→	const path = join(dir, "credentials.json");
196→	try {
197→		const { readFileSync } = require("node:fs");
198→		const content = readFileSync(path, "utf-8");
199→		return JSON.parse(content);
200→	} catch {
201→		return null;
202→	}
203→}
204→
205→function clearCredentialsFromDir(dir: string): void {
206→	const path = join(dir, "credentials.json");
207→	try {
208→		const { rmSync } = require("node:fs");
209→		rmSync(path);
210→	} catch {
211→		// already gone
212→	}
213→}
